cells.content:
// Exemplo 1: Contar logs por nível
fetch logs, from: now() - 1h
| summarize count = count(), by: {loglevel}

// Exemplo 3: Erros por minuto na última hora
fetch logs, from: now() - 1h
| filter loglevel == "ERROR"
| makeTimeseries {
    errors = countIf(loglevel == "ERROR")
  },
  interval: 5m

// Exemplo 5: Remover campos específicos
fetch logs, from: now() - 1h
| fields -trace_id, -span_id

// Exemplo 6: Descobrir campos disponíveis em logs
fetch logs, from: now() - 1h
| fieldsSummary

